import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

function Home() {
  const [blogs, setBlogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('http://localhost:5003/api/blogs')
      .then(response => response.json())
      .then(data => {
        if (Array.isArray(data)) setBlogs(data);
        else if (data.blogs) setBlogs(data.blogs);
        else setBlogs([]);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }, []);

  if (loading) return <h2>Loading blogs...</h2>;

  return (
    <div style={{ padding: '20px' }}>
      <h1>Blog Era</h1>
      <h2>All Blog Posts</h2>
      {blogs.length === 0 ? (
        <p>No blogs found. Create your first blog post!</p>
      ) : (
        blogs.map(blog => (
          <div key={blog._id} style={{ border: '1px solid #ddd', margin: '10px 0', padding: '15px', borderRadius: '5px' }}>
            <Link to={`/blog/${blog._id}`} style={{ textDecoration: 'none', color: 'black' }}>
              <h3>{blog.title}</h3>
            </Link>
            <p>{blog.content.substring(0, 150)}...</p>
            <small>By: {blog.author?.username || blog.author?.name || 'Unknown'}</small>
          </div>
        ))
      )}
    </div>
  );
}

export default Home;
